async function createAgentChatToolLedgerRun(env, p) {
  const { tenantId, workspaceId, userId, sessionId, modelKey, stepsTotal } = p;
  const wfId = await resolveWorkspaceCapabilityShellWorkflowId(env);
  if (!wfId || !tenantId || !workspaceId) return null;
  const runId = `wrun_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
  const cols = await pragmaAgentsamWorkflowRunColumnSet(env.DB);
  const hbFrag = cols.has('heartbeat_at') ? ', heartbeat_at' : '';
  const hbVal = cols.has('heartbeat_at') ? ', unixepoch()' : '';
  const startedSec = Math.floor(Date.now() / 1000);
  await env.DB.prepare(
    `INSERT INTO agentsam_workflow_runs (
      id, workflow_id, workflow_key, display_name, tenant_id, workspace_id,
      user_id, session_id, trigger_type, status,
      input_json, output_json, step_results_json, steps_total, steps_completed,
      input_tokens, output_tokens, cost_usd, supabase_sync_status,
      model_used, started_at, created_at, updated_at
      ${hbFrag}
    ) VALUES (
      ?, ?, ?, ?, ?, ?,
      ?, ?, 'agent', 'running',
      ?, '{}', '[]', ?, 0,
      0, 0, 0, 'pending',
      ?, unixepoch(), datetime('now'), datetime('now')
      ${hbVal}
    )`,
  )
    .bind(
      runId,
      wfId,
      AGENT_CHAT_TOOL_LEDGER_WORKFLOW_KEY,
      'Agent chat · tool session',
      String(tenantId).trim(),
      String(workspaceId).trim(),
      userId != null ? String(userId) : null,
      sessionId != null ? String(sessionId) : null,
      JSON.stringify({ model_key: modelKey, session_id: sessionId }),
      Math.max(1, Number(stepsTotal) || 1),
      modelKey != null ? String(modelKey) : null,
    )
    .run();
  return {
    runId,
    workflowId: wfId,
    steps: [],
    startedAt: Date.now(),
    startedSec,
    stepsTotal: Math.max(1, Number(stepsTotal) || 1),
    hasHeartbeat: cols.has('heartbeat_at'),
    tenantId: String(tenantId).trim(),
    workspaceId: String(workspaceId).trim(),
  };
}

async function appendAgentChatToolLedgerStep(env, emit, ledger, stepEntry) {
  if (!ledger?.runId || !env?.DB) return;
  ledger.steps.push(stepEntry);
  const stepJson = JSON.stringify(ledger.steps);
  const outSummary = {
    last_tool: stepEntry.tool_name,
    last_ok: stepEntry.ok,
    steps_completed: ledger.steps.length,
  };
  let sql = `UPDATE agentsam_workflow_runs SET
    step_results_json = ?,
    steps_completed = ?,
    output_json = ?,
    updated_at = datetime('now')`;
  const binds = [stepJson, ledger.steps.length, JSON.stringify(outSummary)];
  if (ledger.hasHeartbeat) {
    sql += ', heartbeat_at = unixepoch()';
  }
  sql += ' WHERE id = ?';
  binds.push(ledger.runId);
  await env.DB.prepare(sql).bind(...binds).run();
  emit('workflow_step', {
    run_id: ledger.runId,
    node_key: stepEntry.tool_name,
    current_node_key: stepEntry.tool_name,
    steps_completed: ledger.steps.length,
    steps_total: ledger.stepsTotal,
    ok: stepEntry.ok,
    output_preview: String(stepEntry.output_preview || '').slice(0, 4000),
  });
}

async function finalizeAgentChatToolLedger(env, ctx, emit, ledger, { ok, errorMessage }) {
  if (!ledger?.runId || !env?.DB) return;
  const duration = Math.max(0, Date.now() - ledger.startedAt);
  const err = ok ? null : String(errorMessage || 'agent_tool_session_failed').slice(0, 4000);
  let sql = `UPDATE agentsam_workflow_runs SET
    status = ?,
    duration_ms = ?,
    completed_at = unixepoch(),
    error_message = ?,
    updated_at = datetime('now')`;
  const binds = [ok ? 'completed' : 'failed', duration, err];
  if (ledger.hasHeartbeat) {
    sql += ', heartbeat_at = unixepoch()';
  }
  sql += ' WHERE id = ?';
  binds.push(ledger.runId);
  await env.DB.prepare(sql).bind(...binds).run();
  if (ok) {
    emit('workflow_complete', {
      run_id: ledger.runId,
      status: 'completed',
      message: `Executed ${ledger.steps.length} tool call(s).`,
    });
  } else {
    emit('workflow_error', {
      run_id: ledger.runId,
      status: 'failed',
      message: err || 'failed',
    });
  }
  const runForSb = {
    id: ledger.runId,
    workflow_key: AGENT_CHAT_TOOL_LEDGER_WORKFLOW_KEY,
    display_name: 'Agent chat · tool session',
    tenant_id: ledger.tenantId,
    workspace_id: ledger.workspaceId,
    status: ok ? 'completed' : 'failed',
    started_at: ledger.startedSec,
    completed_at: Math.floor(Date.now() / 1000),
    duration_ms: duration,
    cost_usd: 0,
    input_tokens: 0,
    output_tokens: 0,
    error_message: err,
    step_results_json: JSON.stringify(ledger.steps),
  };
  // Supabase RPC is best-effort for UX; D1 row is updated inside syncWorkflowRunToSupabase via
  // patchD1WorkflowRunSupabaseMirrorState (synced / failed, optional supabase_run_id).
  const p = syncWorkflowRunToSupabase(env, runForSb);
  if (ctx?.waitUntil) ctx.waitUntil(p);
  else await p;
}

async function loadToolsForRequest(env, modeSlug, _intent, opts = {}) {
  const lim = Math.max(1, Math.min(200, Number(opts.limit || 20) || 20));
  if (!env.DB) return { tools: [] };
  const policy = await loadModeToolPolicy(env, modeSlug);
  const mcpScope = {
    userId: opts.userId,
    tenantId: opts.tenantId,
    workspaceId: opts.workspaceId,
    personUuid: opts.personUuid,
  };
  let rows = await selectAgentsamMcpToolsList(env.DB, mcpScope, lim);
  const uid = opts.userId != null ? String(opts.userId).trim() : '';
  const wsId = opts.workspaceId != null ? String(opts.workspaceId).trim() : '';
  const tid = opts.tenantId != null ? String(opts.tenantId).trim() : '';
  const pid = opts.personUuid != null ? String(opts.personUuid).trim() : '';
  if (wsId && (uid || tid || pid)) {
    try {
      const keys = await collectAllowlistToolKeysForScope(env.DB, {
        userId: uid,
        workspaceId: wsId,
        tenantId: tid,
        personUuid: pid,
      });
      if (keys.size) {
        rows = rows.filter((r) => keys.has(String(r.tool_name || '').trim()));
      }
    } catch (e) {
      console.warn('[agent] mcp allowlist', e?.message ?? e);
    }
  }
  if (policy.allowTools.length) {
    const allow = new Set(policy.allowTools);
    rows = rows.filter((r) => allow.has(String(r.tool_name)));
  }
  if (policy.denyTools.length) {
    const deny = new Set(policy.denyTools);
    rows = rows.filter((r) => !deny.has(String(r.tool_name)));
  }
  const tools = rows.map((r) => ({
    name: String(r.tool_name),
    description: String(r.description || ''),
    input_schema: parseJsonSafe(r.input_schema, { type: 'object', properties: {} }),
    tool_category: String(r.tool_category || 'builtin'),
    requires_approval: Number(r.requires_approval || 0) === 1,
  }));
  return { tools };
}

function inferRiskLevel(toolName, category = '', rowRiskLevel = '') {
  const r = String(rowRiskLevel || '').toLowerCase();
  if (r === 'critical' || r === 'high') return r;
  const t = String(toolName || '').toLowerCase();
  const c = String(category || '').toLowerCase();
  if (WRITE_LIKE_PREFIXES.some((p) => t.startsWith(p))) return 'high';
  if (TERM_WRITE_TOOLS.has(t)) return 'high';
  if (c === 'terminal' || c === 'deploy') return 'high';
  if (c === 'd1' || c === 'r2') return 'medium';
  return 'low';
}

async function validateToolCall(env, modeSlug, toolName, mcpRuntimeContext = {}, userPolicy = null) {
  const name = String(toolName || '').trim();
  if (!name) {
    return {
      allowed: false,
      reason: 'missing tool name',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: null,
    };
  }
  const uid = mcpRuntimeContext.userId != null ? String(mcpRuntimeContext.userId).trim() : '';
  const ws =
    mcpRuntimeContext.workspaceId != null ? String(mcpRuntimeContext.workspaceId).trim() : '';
  const policyRow = userPolicy || (await loadAgentSamUserPolicy(env, uid, ws));

  if (isSubagentToolName(name) && Number(policyRow.allow_subagent_spawn ?? 1) !== 1) {
    return {
      allowed: false,
      reason: 'subagent spawn disabled by policy',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: null,
    };
  }

  const policy = await loadModeToolPolicy(env, modeSlug);
  if (policy.denyTools.includes(name)) {
    return {
      allowed: false,
      reason: 'blocked by mode policy',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: null,
    };
  }
  if (policy.allowTools.length && !policy.allowTools.includes(name)) {
    return {
      allowed: false,
      reason: 'not in mode allowlist',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: null,
    };
  }
  let row = null;
  if (env.DB) {
    const scope = {
      userId: mcpRuntimeContext.userId,
      tenantId: mcpRuntimeContext.tenantId,
      workspaceId: mcpRuntimeContext.workspaceId,
      personUuid: mcpRuntimeContext.personUuid,
    };
    row = await selectAgentsamMcpToolRow(env.DB, scope, name);
    if (row && Number(row.enabled || 0) !== 1) {
      return {
        allowed: false,
        reason: 'tool disabled',
        riskLevel: 'blocked',
        requiresConfirmation: false,
        mcpToolId: row?.id ?? null,
      };
    }
  }

  const allowRes = await isToolAllowedByAllowlist(
    env,
    policyRow,
    {
      userId: mcpRuntimeContext.userId,
      workspaceId: mcpRuntimeContext.workspaceId,
      tenantId: mcpRuntimeContext.tenantId,
      personUuid: mcpRuntimeContext.personUuid,
      isSuperadmin: !!mcpRuntimeContext.isSuperadmin,
    },
    name,
    row,
    { agentMode: String(modeSlug || '').toLowerCase() === 'agent' },
  );
  if (!allowRes.allowed) {
    return {
      allowed: false,
      reason: allowRes.reason || 'tool not in allowlist',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: row?.id ?? null,
    };
  }

  const riskLevel = inferRiskLevel(name, row?.tool_category, row?.risk_level);
  if (!isToolAllowedByPolicyRisk(policyRow, riskLevel)) {
    return {
      allowed: false,
      reason: 'blocked by tool_risk_level_max',
      riskLevel: 'blocked',
      requiresConfirmation: false,
      mcpToolId: row?.id ?? null,
    };
  }

  let registryRequiresApproval = false;
  if (env.DB && ws) {
    const appr = await env.DB.prepare(
      `SELECT requires_approval FROM agentsam_mcp_tools
       WHERE tool_key = ? AND workspace_id = ? AND COALESCE(is_active, 1) = 1
       LIMIT 1`,
    )
      .bind(name, ws)
      .first()
      .catch(() => null);
    registryRequiresApproval = Number(appr?.requires_approval || 0) === 1;
  }

  const requiresConfirmation = registryRequiresApproval || policy.requireApprovalTools.includes(name);
  return {
    allowed: true,
    reason: 'allowed',
    riskLevel,
    requiresConfirmation,
    mcpToolId: row?.id ?? null,
  };
}

async function dispatchToolCall(env, toolName, input, context = {}) {
  const t0 = Date.now();
  const cached = await tryReadAgentsamToolCache(env, {
    workspaceId: context.workspaceId,
    tenantId: context.tenantId,
    toolName,
    toolInput: input,
  });
  if (cached.hit) return cached.value;

  const sess = {
    user_id: context.userId,
    workspace_id: context.workspaceId,
    workspaceId: context.workspaceId,
    tenant_id: context.tenantId,
    session_id: context.sessionId,
    person_uuid: context.personUuid,
    is_superadmin: context.isSuperadmin,
  };
  const params = {
    ...(input && typeof input === 'object' ? input : {}),
    session: sess,
    session_id: context.sessionId || input?.session_id || null,
    tenant_id: context.tenantId || input?.tenant_id || null,
    user_id: context.userId || input?.user_id || null,
    workspace_id: context.workspaceId ?? input?.workspace_id ?? null,
    person_uuid: context.personUuid ?? input?.person_uuid ?? null,
    request: context.request || null,
  };
  const out = await runBuiltinTool(env, toolName, params);
  if (out && typeof out === 'object' && out.error) {
    throw new Error(typeof out.error === 'string' ? out.error : JSON.stringify(out.error));
  }
  await writeAgentsamToolCacheAfterSuccess(env, {
    workspaceId: context.workspaceId,
    tenantId: context.tenantId,
    toolName,
    toolInput: input,
    toolOutput: out,
    durationMs: Date.now() - t0,
    execErr: null,
  });
  return out;
}

/** Per-tool wall-clock budget for Promise.race around dispatchToolCall (ms). */
function resolveToolExecutionBudgetMs(toolName, input) {
  const n = String(toolName || '').toLowerCase();
  const inp = input && typeof input === 'object' ? input : {};
  const rawTimeout = inp.timeout_ms != null ? Number(inp.timeout_ms) : NaN;
  const terminalNames = new Set(['terminal_run', 'terminal_execute', 'run_command', 'bash']);
  if (terminalNames.has(n)) {
    if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout < 20000) return Math.floor(rawTimeout);
    return 20000;
  }
  if (
    n === 'd1_query' ||
    n === 'd1_explain' ||
    n === 'd1_schema_introspect' ||
    (n.startsWith('d1_') && n.includes('query'))
  ) {
    if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout <= 10000) return Math.floor(rawTimeout);
    return 10000;
  }
  if (n.startsWith('r2_')) {
    if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout < 20000) return Math.floor(rawTimeout);
    return 20000;
  }
  if (
    n.startsWith('browser_') ||
    n.startsWith('playwright') ||
    n.startsWith('cdt_') ||
    n === 'preview_in_browser' ||
    n === 'playwright_screenshot'
  ) {
    if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout < 30000) return Math.floor(rawTimeout);
    return 30000;
  }
  if (n.startsWith('github_')) {
    if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout < 30000) return Math.floor(rawTimeout);
    return 30000;
  }
  if (Number.isFinite(rawTimeout) && rawTimeout > 0 && rawTimeout < 30000) return Math.floor(rawTimeout);
  return 30000;
}

async function dispatchToolCallWithBudget(env, toolName, input, context, budgetMs) {
  let tid;
  const err = /** @type {Error & { code?: string; budgetMs?: number }} */ (
    Object.assign(new Error(`Tool timed out after ${budgetMs}ms`), {
      code: 'tool_timeout',
      budgetMs,
    })
  );
  try {
    return await Promise.race([
      dispatchToolCall(env, toolName, input, context),
      new Promise((_, reject) => {
        tid = setTimeout(() => reject(err), budgetMs);
      }),
    ]);
  } finally {
    if (tid) clearTimeout(tid);
  }
}

