    const limit = body.limit;

    try {
      const { embed_model, results } = await searchCuratedAgentMemory(env, {
        query: q,
        workspace_id,
        tenant_id: tenant_id || null,
        user_id: filter_user_id ? String(identity.userId || '').trim() || null : user_id || null,
