      return jsonResponse({
        ok: true,
        query: q,
        embed_model,
        workspace_id,
        tenant_id: tenant_id || null,
        count: results.length,
        results,
      });
    } catch (e) {
      const msg = e instanceof Error ? e.message : String(e);
      const lower = msg.toLowerCase();
