function normalizeSearchRow(row, origin) {
  const similarity = Number(row.similarity ?? row.score ?? 0);
  const text =
    row.content ||
    row.summary ||
    row.body ||
    row.text ||
    '';
  const source = row.source || row.source_type || origin;
  return {
    id: row.id ?? row.session_id ?? null,
    content: text,
    source,
    title: row.title ?? null,
    similarity,
    _origin: origin,
  };
}

function mergeDedupeSort(rows) {
  const byHash = new Map();
  for (const r of rows) {
    const h = unifiedRagContentHash(r.content || JSON.stringify(r));
    const prev = byHash.get(h);
    if (!prev || r.similarity > prev.similarity) byHash.set(h, r);
  }
  return Array.from(byHash.values()).sort((a, b) => b.similarity - a.similarity);
}

/**
 * Internal unified search (Hyperdrive RPCs + OpenAI embed).
 */
export async function runUnifiedRagQuery(env, { query, tenantId, threshold, limit, includeSessions }) {
  const agentId = ragAgentId(env);
  if (!agentId) {
    return { results: [], error: 'RAG_AGENT_ID not configured' };
  }
  const q = String(query || '').trim();
  if (!q) return { results: [], error: 'empty query' };

  let vec;
  try {
    vec = await openaiCreateEmbedding(env, q);
  } catch (e) {
    const msg = e?.message ?? String(e);
    console.warn('[rag] runUnifiedRagQuery embed:', msg);
    return { results: [], error: msg };
  }
  const vecLit = vectorLiteral(vec);
  const dim = vec.length;
  if (!Number.isFinite(dim) || dim < 1 || dim > 16000) {
    return { results: [], error: 'invalid embedding dimensions' };
  }
  const vecSqlType = `vector(${dim})`;

  const lim = Math.min(Math.max(1, limit || 10), 50);
  const thr = typeof threshold === 'number' ? threshold : 0.7;

  const sqlCtx = `SELECT * FROM public.search_all_context($1::${vecSqlType}, $2::double precision, $3::integer, $4::text)`;
  const sqlSess = `SELECT * FROM public.match_session_summaries($1::${vecSqlType}, $2::text, $3::text, $4::double precision, $5::integer)`;

  const loadCtxRows = async () => {
    try {
      return await withPg(env, async (client) => {
        const res = await client.query(sqlCtx, [vecLit, thr, lim, agentId]);
        return res.rows || [];
      });
    } catch (e) {
      console.warn('[rag] search_all_context failed:', e?.message ?? e);
      return [];
    }
  };

  const loadSessRows = async () => {
    if (!includeSessions || !tenantId) return [];
    try {
      return await withPg(env, async (client) => {
        const res = await client.query(sqlSess, [vecLit, tenantId, agentId, thr, 5]);
        return res.rows || [];
      });
    } catch (e) {
      console.warn('[rag] match_session_summaries failed:', e?.message ?? e);
      return [];
    }
  };

  const [ctxRows, sessRows] = await Promise.all([loadCtxRows(), loadSessRows()]);
  const merged = [
    ...(ctxRows || []).map((r) => normalizeSearchRow(r, 'context')),
    ...(sessRows || []).map((r) => normalizeSearchRow(r, 'session')),
  ];
  const results = mergeDedupeSort(merged);
  return { results, embeddingDims: vec.length };
}

/**
 * Agent-facing RAG (replaces Vectorize / D1 chunk leg).
 */
export async function unifiedRagSearch(env, query, opts = {}) {
  const q = String(query || '').trim();
  if (!q || !env.HYPERDRIVE?.connectionString || !env.OPENAI_API_KEY) {
    return { matches: [], results: [], count: 0, _error: 'missing_bindings' };
  }
  const topK = Math.min(Math.max(1, opts.topK || 8), 24);
  const _t0 = Date.now();
  const tenantId = opts.tenantId != null && String(opts.tenantId).trim() !== '' ? String(opts.tenantId).trim() : null;
  const workspaceId =
    opts.workspaceId != null && String(opts.workspaceId).trim() !== '' ? String(opts.workspaceId).trim() : null;
  const sessionId =
    opts.sessionId != null && String(opts.sessionId).trim() !== '' ? String(opts.sessionId).trim() : null;
  const reqLimit = Math.max(topK, 10);
  const { results, error, embeddingDims } = await runUnifiedRagQuery(env, {
    query: q,
    tenantId,
    threshold: 0.7,
    limit: reqLimit,
    includeSessions: true,
  });
  const latencyMs = Date.now() - _t0;
  if (error) {
    return { matches: [], results: [], count: 0, _error: error };
  }
  const sliced = results.slice(0, topK);

  if (tenantId) {
    const sims = sliced.map((r) => r.similarity).filter((n) => Number.isFinite(n));
    const topSim = sims.length ? Math.max(...sims) : null;
    const avgSim = sims.length ? sims.reduce((a, b) => a + b, 0) / sims.length : null;
    const sourcesHit = [...new Set(sliced.map((r) => String(r.source || '')).filter(Boolean))];
    await logSemanticSearch(env, {
      searchFn: 'unified_rag_search',
      tenantId,
      sessionId,
      queryPreview: q,
      matchThreshold: 0.7,
      matchCountRequested: reqLimit,
      matchCountReturned: sliced.length,
      topSimilarity: topSim,
      avgSimilarity: avgSim,
      sourcesHit,
      latencyMs,
      metadata: {
        workspace_id: workspaceId,
        embed_model: ragEmbeddingModel(env) || null,
        embedding_dims: embeddingDims ?? null,
        rag_documents_project_id: ragDocumentsProjectId(env) || null,
      },
    });
  }

  return {
    matches: sliced.map((x) => {
      const tag = x.source ? `[${x.source}] ` : '';
      return `${tag}${x.content || ''}`.trim();
    }),
    results: sliced.map((x) => ({
      text: x.content,
      source: x.id,
      source_type: x._origin === 'session' ? 'supabase_session_summaries' : `supabase_${x.source || 'context'}`,
      score: Math.round(x.similarity * 1000) / 1000,
    })),
    count: sliced.length,
    _meta: { duration_ms: latencyMs },
  };
}

export function chunkMarkdown(text, maxChars = RAG_CHUNK_MAX_CHARS, overlap = RAG_CHUNK_OVERLAP) {
  const chunks = [];
  const sections = text.split(/(?=^##?\s)/m).map((s) => s.trim()).filter(Boolean);
  for (const section of sections) {
    if (section.length <= maxChars) {
      chunks.push(section);
      continue;
    }
    let start = 0;
    while (start < section.length) {
      const end = Math.min(start + maxChars, section.length);
      const slice = section.slice(start, end);
      if (slice.trim()) chunks.push(slice.trim());
      start = end - (end < section.length ? overlap : 0);
    }
  }
  return chunks.length ? chunks : [text.slice(0, maxChars)];
}

export async function compactAgentChatsToR2(env) {
  if (!env.DB || !env.R2) return { error: 'DB or R2 missing' };
  const cutoff = Math.floor(Date.now() / 1000) - RAG_COMPACT_HOURS * 3600;
  const out = await env.DB.prepare(`SELECT conversation_id, role, content FROM agent_messages WHERE created_at < ?`)
    .bind(cutoff)
    .all();
  const rows = out?.results || [];
  return { conversations_compacted: rows.length };
}

/**
 * POST /api/rag/ingest | /api/rag/search | /api/rag/sync | /api/search (POST)
 */
export async function handleRagApi(request, url, env, _ctx) {
  const path = url.pathname.replace(/\/$/, '') || '/';
  const method = request.method;

  if (method === 'OPTIONS') {
    return new Response(null, { status: 204, headers: { 'Access-Control-Allow-Origin': '*' } });
  }

  try {
    if (path === '/api/search' && method === 'POST') {
      return handleRagSearchRoute(request, env);
    }
    if (path === '/api/rag/ingest' && method === 'POST') {
      return handleRagIngest(request, env);
    }
    if (path === '/api/rag/search' && method === 'POST') {
      return handleRagSearchRoute(request, env);
    }
    if (path === '/api/rag/sync' && method === 'POST') {
      return handleRagSync(request, env);
    }
    return jsonResponse({ error: 'Not found' }, 404);
  } catch (e) {
    console.warn('[rag]', e?.message ?? e);
    return jsonResponse({ error: e?.message || 'RAG error' }, 500);
  }
}

async function handleRagIngest(request, env) {
  const rawBody = await request.text();
  const sig =
    request.headers.get('x-supabase-signature') || request.headers.get('X-Supabase-Signature') || '';
  const isWebhook = !!sig;
  if (isWebhook) {
    const secret = env.SUPABASE_WEBHOOK_SECRET;
    if (!secret || !(await verifySupabaseWebhookSignature(secret, rawBody, sig))) {
      return jsonResponse({ error: 'Invalid webhook signature' }, 401);
    }
  } else {
    const user = await getAuthUser(request, env);
    if (!user) return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  let body;
  try {
    body = JSON.parse(rawBody || '{}');
  } catch {
    return jsonResponse({ error: 'Invalid JSON' }, 400);
  }

  const record = body.record || body;
  const content = String(record.content ?? body.content ?? '').trim();
  const source = String(record.source ?? body.source ?? '').trim();
  const title = String(record.title ?? body.title ?? (source || 'untitled')).slice(0, 500);
  const metadata =
    typeof record.metadata === 'object' && record.metadata !== null
      ? record.metadata
      : typeof body.metadata === 'object' && body.metadata !== null
        ? body.metadata
        : {};

  if (!content || !source) {
    return jsonResponse({ error: 'content and source required' }, 400);
  }

  const projectId = ragDocumentsProjectId(env);
  if (!projectId) return jsonResponse({ error: 'RAG_DOCUMENTS_PROJECT_ID not configured' }, 503);

  const dims = ragEmbeddingDims(env);
  if (!Number.isFinite(dims)) return jsonResponse({ error: 'RAG_EMBEDDING_DIMENSIONS not configured' }, 503);

  try {
    const embedding = await openaiCreateEmbedding(env, content);
    await upsertDocument(env, { source, title, content, embedding, projectId, metadata });

    const folder = resolveAutoragFolder(env, metadata);
    const r2Key = `${folder}${safeObjectSuffix(source)}.txt`;
    try {
      await r2PutObjectText(env, r2Key, content);
    } catch (e) {
      console.warn('[rag] R2 put skipped:', e?.message ?? e);
    }

    await d1RagIngestLog(env, { source, status: 'success', chunks: 1 });

    return jsonResponse({ ok: true, source, dims: embedding.length });
  } catch (e) {
    await d1RagIngestLog(env, { source, status: `error:${String(e?.message || e).slice(0, 80)}`, chunks: 0 });
    throw e;
  }
}

async function handleRagSearchRoute(request, env) {
  const user = await getAuthUser(request, env);
  if (!user) return jsonResponse({ error: 'Unauthorized' }, 401);

  const body = await request.json().catch(() => ({}));
  const query = String(body.query || '').trim();
  if (!query) return jsonResponse({ error: 'query required' }, 400);

  const threshold = typeof body.threshold === 'number' ? body.threshold : 0.7;
  const limit = typeof body.limit === 'number' ? body.limit : 10;
  const includeSessions = !!body.include_sessions;
  let tenantId = String(body.tenant_id || '').trim() || null;
  if (!tenantId && user.tenant_id) tenantId = String(user.tenant_id).trim();
  if (!tenantId && user.id) {
    const fromDb = await fetchAuthUserTenantId(env, user.id);
    if (fromDb) tenantId = fromDb;
  }

  const tSearch = Date.now();
  const { results, error: searchErr, embeddingDims } = await runUnifiedRagQuery(env, {
    query,
    tenantId,
    threshold,
    limit,
    includeSessions,
  });
  const latencyMs = Date.now() - tSearch;
  if (searchErr) return jsonResponse({ error: searchErr }, searchErr === 'empty query' ? 400 : 503);

  const sims = results.map((r) => r.similarity).filter((n) => Number.isFinite(n));
  const topSim = sims.length ? Math.max(...sims) : null;
  const avgSim = sims.length ? sims.reduce((a, b) => a + b, 0) / sims.length : null;
  const sourcesHit = [...new Set(results.map((r) => String(r.source || '')).filter(Boolean))];

  await logSemanticSearch(env, {
    searchFn: 'api.rag.search',
    tenantId,
    sessionId: user.session_id ?? null,
    queryPreview: query,
    matchThreshold: threshold,
    matchCountRequested: limit,
    matchCountReturned: results.length,
    topSimilarity: topSim,
    avgSimilarity: avgSim,
    sourcesHit,
    latencyMs,
    metadata: {
      include_sessions: includeSessions,
      embed_model: ragEmbeddingModel(env) || null,
      embedding_dims: embeddingDims ?? null,
      rag_documents_project_id: ragDocumentsProjectId(env) || null,
    },
  });

  return jsonResponse({
    ok: true,
    results,
    count: results.length,
    query_preview: query.slice(0, 100),
  });
}

async function handleRagSync(request, env) {
  if (!verifyInternalSecret(request, env)) {
    return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  const projectId = ragDocumentsProjectId(env);
  if (!projectId) return jsonResponse({ error: 'RAG_DOCUMENTS_PROJECT_ID not configured' }, 503);

  let keys;
  try {
    keys = await r2ListAllObjectKeys(env);
  } catch (e) {
    return jsonResponse({ ok: false, error: e?.message || 'list failed' }, 500);
  }

  const synced = [];
  const skipped = [];
  const errors = [];

  const pending = [];
  for (const key of keys) {
    if (!key || key.endsWith('/')) continue;
    pending.push(key);
  }

  const batchSize = 10;
  for (let i = 0; i < pending.length; i += batchSize) {
    const batch = pending.slice(i, i + batchSize);
    await Promise.all(
      batch.map(async (sourceKey) => {
        try {
          const exists = await documentSourceExists(env, sourceKey, projectId);
          if (exists) {
            skipped.push(sourceKey);
            return;
          }
          const text = await r2GetObjectText(env, sourceKey);
          const embedding = await openaiCreateEmbedding(env, text);
          const title = sourceKey.split('/').pop() || sourceKey;
          await upsertDocument(env, {
            source: sourceKey,
            title,
            content: text,
            embedding,
            projectId,
            metadata: { folder: sourceKey.includes('/') ? `${sourceKey.slice(0, sourceKey.lastIndexOf('/') + 1)}` : 'knowledge/' },
          });
          synced.push(sourceKey);
          await d1RagIngestLog(env, { source: sourceKey, status: 'success', chunks: 1 });
        } catch (e) {
          errors.push({ key: sourceKey, error: e?.message || String(e) });
        }
      })
    );
  }

  return jsonResponse({ ok: true, synced: synced.length, skipped: skipped.length, errors });
}

/**
 * Insert one curated row into `public.agent_memory` with an OpenAI embedding (same model/dims as RAG).
 * Requires HYPERDRIVE, OPENAI_API_KEY, OPENAI_API_BASE_URL, RAG_OPENAI_EMBEDDING_MODEL, RAG_EMBEDDING_DIMENSIONS.
 *
 * @param {any} env
 * @param {{
 *   content: string,
 *   session_id: string,
 *   role?: string,
 *   agent_id?: string,
 *   metadata?: Record<string, unknown>,
 *   workspace_id?: string | null,
 *   tenant_id?: string | null,
 *   user_id?: string | null,
 * }} params
 * @returns {Promise<{ id: string, embedding_dims: number, embed_model: string }>}
 */
export async function insertCuratedAgentMemory(env, params) {
  const content = String(params.content || '').trim();
  if (!content) throw new Error('content required');
  const session_id = String(params.session_id || '').trim();
  if (!session_id) throw new Error('session_id required');

  const roleRaw = String(params.role || 'assistant').toLowerCase();
  if (roleRaw !== 'user' && roleRaw !== 'assistant') {
    throw new Error('role must be user or assistant');
  }
  const agent_id = String(params.agent_id || 'agent-sam').trim() || 'agent-sam';
  const metadata =
    params.metadata && typeof params.metadata === 'object' && params.metadata !== null && !Array.isArray(params.metadata)
      ? params.metadata
      : {};

  const workspace_id =
    params.workspace_id != null && String(params.workspace_id).trim() !== ''
      ? String(params.workspace_id).trim()
      : null;
  const tenant_id =
    params.tenant_id != null && String(params.tenant_id).trim() !== '' ? String(params.tenant_id).trim() : null;
  const user_id =
    params.user_id != null && String(params.user_id).trim() !== '' ? String(params.user_id).trim() : null;

  const embed_model = ragEmbeddingModel(env);
  const expectedDims = ragEmbeddingDims(env);
  if (!embed_model) throw new Error('RAG_OPENAI_EMBEDDING_MODEL not configured');
  if (!Number.isFinite(expectedDims)) throw new Error('RAG_EMBEDDING_DIMENSIONS not configured');

  const embedding = await openaiCreateEmbedding(env, content);
  const dims = embedding.length;
  if (dims !== expectedDims) {
    throw new Error(`embedding length ${dims} does not match RAG_EMBEDDING_DIMENSIONS (${expectedDims})`);
  }

  const vecLit = vectorLiteral(embedding);

  return await withPg(env, async (client) => {
    const ins = await client.query(
      `INSERT INTO public.agent_memory (
        session_id, agent_id, role, content, metadata,
        embedding, workspace_id, embed_model, tenant_id, user_id
      ) VALUES ($1, $2, $3, $4, $5::jsonb, $6::vector, $7, $8, $9, $10)
      RETURNING id`,
      [
        session_id,
        agent_id,
        roleRaw,
        content,
        metadata,
        vecLit,
        workspace_id,
        embed_model,
        tenant_id,
        user_id,
      ],
    );
    const id = ins.rows?.[0]?.id;
    if (!id) throw new Error('insert returned no id');

    const verify = await client.query(
      `SELECT vector_dims(embedding) AS dims FROM public.agent_memory WHERE id = $1::uuid`,
      [id],
    );
    const vd = verify.rows?.[0]?.dims;
    if (vd != null && Number(vd) !== expectedDims) {
      throw new Error(`vector_dims check failed: got ${vd}, expected ${expectedDims}`);
    }

    return {
      id: String(id),
      embedding_dims: dims,
      embed_model,
    };
  });
}

/**
 * Semantic-only search on `public.agent_memory` (cosine distance via pgvector).
 * Unlike `search_agent_memory`, this does **not** require trigram `%` on query text,
 * so paraphrased questions still match.
 *
 * @param {any} env
 * @param {{
 *   query: string,
 *   workspace_id: string,
 *   tenant_id: string | null,
 *   user_id?: string | null,
 *   session_id?: string | null,
 *   limit?: number,
 * }} opts
 * @returns {Promise<{ embed_model: string, results: Array<Record<string, unknown>> }>}
 */
export async function searchCuratedAgentMemory(env, opts) {
  const query = String(opts.query || '').trim();
  if (!query) throw new Error('query required');
  const workspace_id = String(opts.workspace_id || '').trim();
  if (!workspace_id) throw new Error('workspace_id required');

  const tenant_id =
    opts.tenant_id != null && String(opts.tenant_id).trim() !== '' ? String(opts.tenant_id).trim() : null;
  const user_id =
    opts.user_id != null && String(opts.user_id).trim() !== '' ? String(opts.user_id).trim() : null;
  const session_id =
    opts.session_id != null && String(opts.session_id).trim() !== '' ? String(opts.session_id).trim() : null;

  let limit = Number(opts.limit);
  if (!Number.isFinite(limit) || limit < 1) limit = 10;
  if (limit > 50) limit = 50;

  const embed_model = ragEmbeddingModel(env);
  if (!embed_model) throw new Error('RAG_OPENAI_EMBEDDING_MODEL not configured');
  if (!Number.isFinite(ragEmbeddingDims(env))) throw new Error('RAG_EMBEDDING_DIMENSIONS not configured');

  const embedding = await openaiCreateEmbedding(env, query);
  const vecLit = vectorLiteral(embedding);

  return await withPg(env, async (client) => {
    const sql = `
      SELECT
        am.id,
        am.session_id,
        am.agent_id,
        am.role,
        am.content,
        am.metadata,
        am.created_at,
        am.tenant_id,
        am.workspace_id,
        am.user_id,
        (am.embedding <=> $1::vector)::double precision AS embedding_distance
      FROM public.agent_memory am
      WHERE am.embedding IS NOT NULL
        AND am.workspace_id = $2
        AND ($3::text IS NULL OR am.tenant_id = $3)
        AND ($4::text IS NULL OR am.user_id = $4 OR am.user_id IS NULL)
        AND ($5::text IS NULL OR am.session_id = $5)
      ORDER BY am.embedding <=> $1::vector
      LIMIT $6`;
    const { rows } = await client.query(sql, [vecLit, workspace_id, tenant_id, user_id, session_id, limit]);

    const results = (rows || []).map((r) => {
      const d = r.embedding_distance != null ? Number(r.embedding_distance) : NaN;
      const similarity = Number.isFinite(d) ? Math.max(0, Math.min(1, 1 - d)) : null;
      return {
        id: r.id,
        session_id: r.session_id,
        agent_id: r.agent_id,
        role: r.role,
        content: r.content,
        metadata: r.metadata,
        created_at: r.created_at,
        tenant_id: r.tenant_id,
        workspace_id: r.workspace_id,
        user_id: r.user_id,
        embedding_distance: r.embedding_distance,
        similarity,
      };
    });

    return { embed_model, results };
  });
}

/**
 * POST /api/agent/memory/sync — Supabase webhook: embed new/updated rows.
 */
export async function handleAgentMemorySync(request, env) {
  if (request.method !== 'POST') return jsonResponse({ error: 'Method not allowed' }, 405);
  const rawBody = await request.text();
  const sig =
    request.headers.get('x-supabase-signature') || request.headers.get('X-Supabase-Signature') || '';
  const secret = env.SUPABASE_WEBHOOK_SECRET;
  if (!secret || !(await verifySupabaseWebhookSignature(secret, rawBody, sig))) {
    return jsonResponse({ error: 'Invalid webhook signature' }, 401);
  }

  let body;
  try {
    body = JSON.parse(rawBody || '{}');
  } catch {
    return jsonResponse({ error: 'Invalid JSON' }, 400);
  }

  const record = body.record || body;
  const id = record.id;
  const content = String(record.content || '').trim();
  if (!id || !content) {
    return jsonResponse({ error: 'record.id and record.content required' }, 400);
  }

  const emb = record.embedding;
  const needsEmbedding =
    emb == null || (Array.isArray(emb) && emb.length === 0) || (typeof emb === 'string' && !emb.trim());

  if (!needsEmbedding) {
    await d1RagIngestLog(env, { source: `agent_memory:${id}`, status: 'skipped_has_embedding', chunks: 0 });
    return jsonResponse({ ok: true });
  }

  try {
    const embedding = await openaiCreateEmbedding(env, content);
    const vecLit = vectorLiteral(embedding);
    await withPg(env, async (client) => {
      await client.query(`UPDATE public.agent_memory SET embedding = $1::vector WHERE id = $2::uuid`, [
        vecLit,
        id,
      ]);
    });
    await d1RagIngestLog(env, { source: `agent_memory:${id}`, status: 'success', chunks: 1 });
    return jsonResponse({ ok: true });
  } catch (e) {
    await d1RagIngestLog(env, {
      source: `agent_memory:${id}`,
      status: `error:${String(e?.message || e).slice(0, 80)}`,
      chunks: 0,
    });
    return jsonResponse({ error: e?.message || 'sync failed' }, 500);
  }
}

/**
 * Strict, awaited Supabase sync for Agent Sam workflow runs (server-side only).
 * Schema: agentsam.workflow_runs via PostgREST (Accept-Profile / Content-Profile: agentsam).
 */

export const AGENTSAM_WORKFLOW_RUNS_TABLE = 'agentsam_workflow_runs';

const WORKFLOW_RUNS_PATH = '/rest/v1/workflow_runs';

/** @param {import('@cloudflare/workers-types').D1Database} db */
async function pragmaAgentsamWorkflowRunsColumns(db) {
  try {
    const { results } = await db.prepare(`PRAGMA table_info(${AGENTSAM_WORKFLOW_RUNS_TABLE})`).all();
    return new Set((results || []).map((r) => String(r.name || '').toLowerCase()));
  } catch {
    return new Set();
  }
}

/**
 * Reflect Supabase mirror outcome on the D1 workflow run row (optional columns for older DBs).
 * @param {any} env
 * @param {string} d1RunId
 * @param {{ ok: boolean, supabaseRunId?: string|null, error?: string|null }} outcome
 */
export async function patchD1WorkflowRunSupabaseMirrorState(env, d1RunId, outcome) {
  const db = env?.DB;
  const rid = String(d1RunId || '').trim();
  if (!db || !rid) return;
  const cols = await pragmaAgentsamWorkflowRunsColumns(db);
  const fragments = [];
  const binds = [];

  if (cols.has('updated_at')) {
    fragments.push(`updated_at = datetime('now')`);
  }

  if (outcome.ok) {
    if (cols.has('supabase_sync_status')) fragments.push(`supabase_sync_status = 'synced'`);
    if (cols.has('supabase_sync_error')) fragments.push(`supabase_sync_error = NULL`);
    if (cols.has('supabase_synced_at')) fragments.push(`supabase_synced_at = datetime('now')`);
    const sid = outcome.supabaseRunId != null ? String(outcome.supabaseRunId).trim() : '';
    if (sid && cols.has('supabase_run_id')) {
      fragments.push(`supabase_run_id = ?`);
      binds.push(sid);
    }
    if (cols.has('supabase_sync_attempts')) {
      fragments.push(`supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1`);
    }
  } else {
    const msg = String(outcome.error || 'supabase_sync_failed').slice(0, 8000);
    if (cols.has('supabase_sync_status')) fragments.push(`supabase_sync_status = 'failed'`);
    if (cols.has('supabase_sync_error')) {
      fragments.push(`supabase_sync_error = ?`);
      binds.push(msg);
    }
    if (cols.has('supabase_sync_attempts')) {
      fragments.push(`supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1`);
    }
  }

  if (!fragments.length) return;
  binds.push(rid);
  const sql = `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE} SET ${fragments.join(', ')} WHERE id = ?`;
  try {
    await db.prepare(sql).bind(...binds).run();
  } catch (e) {
    console.warn('[agentsam-supabase-sync] patchD1WorkflowRunSupabaseMirrorState', e?.message ?? e);
  }
}

/** @param {string} text */
function parseSupabaseRpcWorkflowRunId(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  try {
    const j = JSON.parse(raw);
    if (j == null) return null;
    if (typeof j === 'string' && j) return j;
    if (typeof j === 'number' && Number.isFinite(j)) return String(j);
    if (typeof j === 'object' && !Array.isArray(j) && j.id != null) return String(j.id);
    if (Array.isArray(j) && j.length) {
      const x = j[0];
      if (typeof x === 'string') return x;
      if (x && typeof x === 'object' && x.id != null) return String(x.id);
    }
  } catch {
    // non-JSON body (rare)
  }
  return null;
}

/**
 * @param {import('@cloudflare/workers-types').D1Result} result
 * @param {string} label
 */
export function assertD1Write(result, label) {
  if (result == null) throw new Error(`[${label}] D1: no result`);
  if (result.success === false) throw new Error(`[${label}] D1: success=false`);
  const changes = result.meta?.changes ?? 0;
  if (changes < 1) throw new Error(`[${label}] D1: expected ≥1 row changed, got ${changes}`);
}

function supabaseRestBase(env) {
  const raw = env?.SUPABASE_URL;
  if (!raw || !String(raw).trim()) throw new Error('SUPABASE_URL is not configured');
  return String(raw).replace(/\/$/, '');
}

function supabaseServiceRole(env) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  if (!key || !String(key).trim()) throw new Error('SUPABASE_SERVICE_ROLE_KEY is not configured');
  return String(key).trim();
}

function supabaseHeaders(env, extra = {}) {
  const key = supabaseServiceRole(env);
  return {
    apikey: key,
    Authorization: `Bearer ${key}`,
    'Content-Type': 'application/json',
    Prefer: 'return=representation',
    'Accept-Profile': 'agentsam',
    'Content-Profile': 'agentsam',
    ...extra,
  };
}

/**
 * Insert a row in agentsam.workflow_runs. Returns the created row (must include id).
 * @param {any} env
 * @param {Record<string, unknown>} runPayload
 */
export async function createSupabaseWorkflowRun(env, runPayload) {
  const base = supabaseRestBase(env);
  const res = await fetch(`${base}${WORKFLOW_RUNS_PATH}`, {
    method: 'POST',
    headers: supabaseHeaders(env),
    body: JSON.stringify(runPayload),
  });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`Supabase workflow_runs insert failed HTTP ${res.status}: ${text.slice(0, 4000)}`);
  }
  let json;
  try {
    json = text ? JSON.parse(text) : [];
  } catch (e) {
    throw new Error(`Supabase insert: invalid JSON: ${String(e?.message || e)}`);
  }
  const row = Array.isArray(json) ? json[0] : json;
  if (!row || row.id == null || String(row.id).trim() === '') {
    throw new Error('Supabase insert returned no id');
  }
  return row;
}

/**
 * PATCH agentsam.workflow_runs by primary key id.
 * @param {any} env
 * @param {string} supabaseRunId
 * @param {Record<string, unknown>} patch
 */
export async function updateSupabaseWorkflowRun(env, supabaseRunId, patch) {
  const id = String(supabaseRunId || '').trim();
  if (!id) throw new Error('updateSupabaseWorkflowRun: supabaseRunId required');
  const base = supabaseRestBase(env);
  const url = `${base}${WORKFLOW_RUNS_PATH}?id=eq.${encodeURIComponent(id)}`;
  const res = await fetch(url, {
    method: 'PATCH',
    headers: supabaseHeaders(env),
    body: JSON.stringify(patch),
  });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`Supabase workflow_runs PATCH failed HTTP ${res.status}: ${text.slice(0, 4000)}`);
  }
  if (res.status === 204) {
    return { ok: true, rows: [] };
  }
  let json;
  try {
    json = text ? JSON.parse(text) : [];
  } catch (e) {
    throw new Error(`Supabase PATCH: invalid JSON: ${String(e?.message || e)}`);
  }
  if (Array.isArray(json) && json.length === 0) {
    throw new Error('Supabase PATCH returned no updated rows');
  }
  return Array.isArray(json) ? json[0] : json;
}

/**
 * After a successful Supabase insert: store id + synced on D1.
 * @param {any} env
 * @param {string} d1RunId
 * @param {string} supabaseRunId
 */
export async function markWorkflowRunSupabaseSynced(env, d1RunId, supabaseRunId) {
  const db = env?.DB;
  if (!db) throw new Error('markWorkflowRunSupabaseSynced: DB not configured');
  const sid = String(supabaseRunId ?? '').trim();
  let result;
  if (sid) {
    result = await db
      .prepare(
        `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
         SET supabase_run_id = ?,
             supabase_sync_status = 'synced',
             supabase_synced_at = datetime('now'),
             supabase_sync_error = NULL,
             supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
         WHERE id = ?`,
      )
      .bind(sid, d1RunId)
      .run();
  } else {
    result = await db
      .prepare(
        `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
         SET supabase_sync_status = 'synced',
             supabase_synced_at = datetime('now'),
             supabase_sync_error = NULL,
             supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
         WHERE id = ?`,
      )
      .bind(d1RunId)
      .run();
  }
  assertD1Write(result, 'markWorkflowRunSupabaseSynced');
}

/**
 * Record Supabase sync failure on the D1 run row.
 * @param {any} env
 * @param {string} d1RunId
 * @param {string} error
 */
const SUPABASE_RPC_FALLBACK_ORIGIN = 'https://dpmuvynqixblxsilnlut.supabase.co';

function restOriginForRpc(env) {
  try {
    return supabaseRestBase(env);
  } catch {
    return SUPABASE_RPC_FALLBACK_ORIGIN.replace(/\/$/, '');
  }
}

/**
 * Fire-and-forget analytics sync to Supabase Postgres RPC (non-fatal; D1 remains source of truth).
 * @param {any} env
 * @param {Record<string, unknown>} run — D1 agentsam_workflow_runs row or compatible object
 */
export async function syncWorkflowRunToSupabase(env, run) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  const db = env?.DB;
  if (!key || !run?.id || !db) return;
  const secToIso = (t) => {
    if (t == null || t === '') return null;
    const n = Number(t);
    if (!Number.isFinite(n)) return null;
    return new Date(n < 1e12 ? n * 1000 : n).toISOString();
  };
  let toolCallsCount = run.tool_calls_count != null ? Number(run.tool_calls_count) : null;
  if (toolCallsCount == null || !Number.isFinite(toolCallsCount)) {
    try {
      const raw = run.step_results_json;
      const arr = typeof raw === 'string' ? JSON.parse(raw || '[]') : raw;
      if (Array.isArray(arr)) toolCallsCount = arr.length;
    } catch {
      toolCallsCount = 0;
    }
  }
  if (!Number.isFinite(toolCallsCount)) toolCallsCount = 0;

  let status = run.status != null ? String(run.status) : '';
  if (status === 'success') status = 'completed';

  try {
    const supabaseRow = await createSupabaseWorkflowRun(env, {
      d1_workflow_id: run.id,
      workflow_key: run.workflow_key ?? '',
      display_name: run.display_name ?? '',
      tenant_id: run.tenant_id ?? '',
      workspace_id:
        run.workspace_id ||
        (env.DEFAULT_WORKSPACE_ID != null && String(env.DEFAULT_WORKSPACE_ID).trim() !== ''
          ? String(env.DEFAULT_WORKSPACE_ID).trim()
          : ''),
      status: status || 'unknown',
      started_at: secToIso(run.started_at),
      completed_at: secToIso(run.completed_at),
      duration_ms: run.duration_ms != null ? Number(run.duration_ms) : null,
      cost_usd: run.cost_usd != null ? Number(run.cost_usd) : 0,
      input_tokens: run.input_tokens != null ? Number(run.input_tokens) : 0,
      output_tokens: run.output_tokens != null ? Number(run.output_tokens) : 0,
      tool_calls_count: toolCallsCount,
      error_message: run.error_message ?? null,
      model_id: run.model_used ?? run.model_id ?? null,
    });

    const supabaseRunId = supabaseRow?.id != null ? String(supabaseRow.id) : null;
    await patchD1WorkflowRunSupabaseMirrorState(env, run.id, { ok: true, supabaseRunId });
  } catch (e) {
    await patchD1WorkflowRunSupabaseMirrorState(env, run.id, {
      ok: false,
      error: e?.message != null ? String(e.message) : String(e),
    });
  }
}

export async function markWorkflowRunSupabaseFailed(env, d1RunId, error) {
  const db = env?.DB;
  if (!db) throw new Error('markWorkflowRunSupabaseFailed: DB not configured');
  const msg = String(error || 'unknown error').slice(0, 8000);
  const result = await db
    .prepare(
      `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
       SET supabase_sync_status = 'failed',
           supabase_sync_error = ?,
           supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
       WHERE id = ?`,
    )
    .bind(msg, d1RunId)
    .run();
  assertD1Write(result, 'markWorkflowRunSupabaseFailed');
}

/**
 * agentsam_memory — prompt injection for chat and scheduled decay (01:00 UTC cron).
 *
 * Returns a markdown-ish block for callers to concatenate **after** the main system prompt
 * (identity + policy strings). Do not prepend ahead of core system instructions.
 */

import {
  logSemanticSearch,
  ragEmbeddingDims,
  ragEmbeddingModel,
  searchAgentMemoryHybrid,
} from '../api/rag.js';
import { compactToolStatsCompacted } from './tool-stats-rollup.js';

const IAM_EMBED_MODEL = '@cf/baai/bge-large-en-v1.5';
/** Default REST origin when env.SUPABASE_URL is unset (matches project Postgres RPC). */
const SUPABASE_REST_FALLBACK = 'https://dpmuvynqixblxsilnlut.supabase.co';

function supabaseRestOrigin(env) {
  const raw = env?.SUPABASE_URL && String(env.SUPABASE_URL).trim();
  if (raw) return raw.replace(/\/$/, '');
  return SUPABASE_REST_FALLBACK;
}

/**
 * @param {any} env
 * @param {number[]} embedding
 * @param {string|null} sessionId
 * @param {string|null} agentId
 * @param {string|null} workspaceId
 * @returns {Promise<any[]>}
 */
export async function recallSemanticMemory(env, embedding, sessionId, agentId, workspaceId) {
  const supabaseKey = env?.SUPABASE_SERVICE_ROLE_KEY;
  if (!supabaseKey || !Array.isArray(embedding) || !embedding.length) return [];
  const supabaseUrl = supabaseRestOrigin(env);
  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/rpc/recall_agent_memory`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${supabaseKey}`,
        apikey: supabaseKey,
      },
      body: JSON.stringify({
        query_embedding: embedding,
        p_session_id: sessionId || null,
        p_agent_id: agentId || null,
        p_workspace_id: workspaceId || null,
        p_limit: 10,
        p_threshold: 0.75,
      }),
    });
    if (!res.ok) return [];
    const json = await res.json().catch(() => []);
    return Array.isArray(json) ? json : [];
  } catch {
    return [];
  }
}

function formatSemanticRecallBlock(rows) {
  const lines = (rows || []).map((r) => {
    if (r == null) return '';
    if (typeof r === 'string') return `- ${r}`;
    const sim = r.similarity != null ? `[${Number(r.similarity).toFixed(3)}] ` : '';
    const text =
      r.content ?? r.text ?? r.value ?? r.memory ?? (typeof r === 'object' ? JSON.stringify(r) : String(r));
    return `- ${sim}${text}`;
  }).filter(Boolean);
  if (!lines.length) return '';
  return `\n## Agent Memory (semantic, ${lines.length} items)\n${lines.join('\n')}\n`;
}

/**
 * Semantic recall via Supabase RPC + Workers AI embedding; falls back to D1 agentsam_memory.
 * @param {any} env
 * @param {string} tenantId
 * @param {{ userMessage?: string, sessionId?: string|null, agentId?: string|null, workspaceId?: string|null }} [ctx]
 */
export async function loadAgentMemoryForPrompt(env, tenantId, ctx = {}) {
  const userMessage = ctx?.userMessage != null ? String(ctx.userMessage) : '';
  const fallback = () => loadAgentMemory(env, tenantId);
  if (!tenantId || !userMessage.trim()) {
    return fallback();
  }

  const workspaceId =
    ctx.workspaceId != null && String(ctx.workspaceId).trim() !== ''
      ? String(ctx.workspaceId).trim()
      : null;

  if (workspaceId) {
    const tHybrid = Date.now();
    const hybridRows = await searchAgentMemoryHybrid(env, userMessage, workspaceId, {});
    const hybridMs = Date.now() - tHybrid;
    const hr = Array.isArray(hybridRows) ? hybridRows : [];
    const hybridSims = hr.map((r) => Number(r.hybrid_score)).filter((n) => Number.isFinite(n));
    const topHybrid = hybridSims.length ? Math.max(...hybridSims) : null;
    const avgHybrid = hybridSims.length ? hybridSims.reduce((a, b) => a + b, 0) / hybridSims.length : null;
    await logSemanticSearch(env, {
      searchFn: 'agent_memory_search',
      tenantId,
      sessionId: ctx.sessionId ?? null,
      queryPreview: userMessage,
      matchThreshold: 0.75,
      matchCountRequested: 10,
      matchCountReturned: hr.length,
      topSimilarity: topHybrid,
      avgSimilarity: avgHybrid,
      sourcesHit: ['agent_memory'],
      latencyMs: hybridMs,
      metadata: {
        workspace_id: workspaceId,
        path: 'hyperdrive_search_agent_memory',
        embed_model: ragEmbeddingModel(env) || null,
        embedding_dims: Number.isFinite(ragEmbeddingDims(env)) ? ragEmbeddingDims(env) : null,
      },
    });
    if (hr.length > 0) {
      console.log('[rag] memory search via', 'hyperdrive');
      const mapped = hr.map((r) => ({
        similarity: r.hybrid_score,
        content: r.content,
      }));
      const block = formatSemanticRecallBlock(mapped);
      return block || fallback();
    }
  }

  console.log('[rag] memory search via', 'vectorize');

  if (!env?.SUPABASE_SERVICE_ROLE_KEY || !env?.AI) {
    return fallback();
  }
  try {
    const tRecall = Date.now();
    const resp = await env.AI.run(IAM_EMBED_MODEL, {
      text: [userMessage.slice(0, 8000)],
    });
    const vecs = resp?.data || resp?.result || [];
    const rawEmb = vecs?.[0];
    const queryEmbedding = Array.isArray(rawEmb)
      ? rawEmb
      : rawEmb != null && typeof rawEmb.length === 'number'
        ? Array.from(rawEmb)
        : null;
    if (!queryEmbedding?.length) return fallback();
    const recalled = await recallSemanticMemory(
      env,
      queryEmbedding,
      ctx.sessionId ?? null,
      ctx.agentId ?? null,
      ctx.workspaceId ?? null,
    );
    const recallMs = Date.now() - tRecall;
    const rec = Array.isArray(recalled) ? recalled : [];
    const recSims = rec.map((r) => Number(r.similarity)).filter((n) => Number.isFinite(n));
    const topRec = recSims.length ? Math.max(...recSims) : null;
    const avgRec = recSims.length ? recSims.reduce((a, b) => a + b, 0) / recSims.length : null;
    await logSemanticSearch(env, {
      searchFn: 'agent_memory_search',
      tenantId,
      sessionId: ctx.sessionId ?? null,
      queryPreview: userMessage,
      matchThreshold: 0.75,
      matchCountRequested: 10,
      matchCountReturned: rec.length,
      topSimilarity: topRec,
      avgSimilarity: avgRec,
      sourcesHit: ['agent_memory'],
      latencyMs: recallMs,
      metadata: {
        workspace_id: workspaceId,
        path: 'supabase_recall_agent_memory',
        embed_model: IAM_EMBED_MODEL,
        embedding_dims: queryEmbedding.length,
      },
    });
    if (!rec.length) return fallback();
    const block = formatSemanticRecallBlock(recalled);
    return block || fallback();
  } catch {
    return fallback();
  }
}

export async function loadAgentMemory(env, tenantId) {
  if (!env?.DB || !tenantId) return '';
  try {
    const rows = await env.DB.prepare(
      `SELECT id, key, value, memory_type, confidence, decay_score
       FROM agentsam_memory
       WHERE tenant_id = ?
         AND decay_score > 0.3
         AND (expires_at IS NULL OR expires_at > unixepoch())
         AND value NOT LIKE '[STALE%'
       ORDER BY
         CASE memory_type
           WHEN 'error' THEN 1
           WHEN 'decision' THEN 2
           WHEN 'fact' THEN 3
           WHEN 'skill' THEN 4
           WHEN 'preference' THEN 5
           WHEN 'project' THEN 6
           ELSE 7
         END,
         confidence DESC,
         decay_score DESC
       LIMIT 20`,
    )
      .bind(String(tenantId))
      .all();

    const list = rows?.results || [];
    if (!list.length) return '';

    const lines = list.map((r) => {
      const t = String(r.memory_type || 'fact').toUpperCase();
      return `[${t}] ${r.key}: ${r.value}`;
    });

    const ids = list.map((r) => r.id).filter(Boolean);
    if (ids.length) {
      const ph = ids.map(() => '?').join(',');
      env.DB.prepare(
        `UPDATE agentsam_memory
         SET recall_count = recall_count + 1,
             last_recalled_at = unixepoch(),
             updated_at = unixepoch()
         WHERE id IN (${ph})`,
      )
        .bind(...ids)
        .run()
        .catch(() => {});
    }

    return `\n## Agent Memory (${list.length} items)\n${lines.join('\n')}\n`;
  } catch (e) {
    console.warn('[agentsam_memory] loadAgentMemory', e?.message ?? e);
    return '';
  }
}

